import React from 'react';
import {
  Box,
  Tabs,
  Tab,
  useTheme
} from '@mui/material';
import { alpha } from '@mui/material/styles';

export interface TabItem {
  label: string;
  value?: string | number;
  disabled?: boolean;
  icon?: React.ReactElement;
  /** Optional numeric badge rendered next to the label (e.g. unread count). */
  badgeCount?: number;
}

interface TabPanelProps {
  children?: React.ReactNode;
  index: number;
  value: number;
  /**
   * When true, the active panel becomes a flex-column that fills its
   * parent's remaining height. Children can use `flex: 1` to take all
   * available space (useful inside flex-constrained dialogs/panels).
   * Opt-in to avoid affecting existing block-layout call sites.
   */
  fullHeight?: boolean;
}

export const TabPanel: React.FC<TabPanelProps> = ({
  children,
  value,
  index,
  fullHeight = false,
  ...other
}) => {
  const active = value === index;
  return (
    <div
      role="tabpanel"
      hidden={!active}
      id={`rounded-tabpanel-${index}`}
      aria-labelledby={`rounded-tab-${index}`}
      style={
        active && fullHeight
          ? { flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column' }
          : undefined
      }
      {...other}
    >
      {active && (
        <Box
          sx={
            fullHeight
              ? { flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column' }
              : undefined
          }
        >
          {children}
        </Box>
      )}
    </div>
  );
};

interface RoundedTabsProps {
  tabs: TabItem[];
  activeTab: number;
  onTabChange: (event: React.SyntheticEvent, newValue: number) => void;
  children?: React.ReactNode;
  size?: 'small' | 'medium' | 'large';
  variant?: 'contained' | 'outlined';
  fullWidth?: boolean;
  sx?: any;
}

const RoundedTabs: React.FC<RoundedTabsProps> = ({
  tabs,
  activeTab,
  onTabChange,
  children,
  size = 'medium',
  variant = 'contained',
  fullWidth = false,
  sx = {}
}) => {
  const theme = useTheme();

  // Size configurations
  const sizeConfig = {
    small: {
      minHeight: 32,
      fontSize: '0.75rem',
      padding: '4px 12px',
      borderRadius: '8px',
      containerPadding: '2px'
    },
    medium: {
      minHeight: 40,
      fontSize: '0.875rem',
      padding: '6px 18px',
      borderRadius: '8px',
      containerPadding: '4px'
    },
    large: {
      minHeight: 48,
      fontSize: '1rem',
      padding: '8px 24px',
      borderRadius: '8px',
      containerPadding: '6px'
    }
  };

  const config = sizeConfig[size];

  // Variant configurations
  const getVariantStyles = () => {
    if (variant === 'outlined') {
      return {
        backgroundColor: 'transparent',
        border: `1px solid ${theme.palette.divider}`,
        '& .MuiTab-root': {
          '&.Mui-selected': {
            backgroundColor: theme.palette.primary.main,
            color: '#ffffff',
            boxShadow: '0 1px 2px rgba(0,0,0,0.3)'
          },
          '&:hover:not(.Mui-selected)': {
            backgroundColor: alpha(theme.palette.primary.main, 0.05),
            color: 'primary.main'
          }
        }
      };
    }

    // Default contained variant
    return {
      backgroundColor: theme.palette.mode === 'light'
        ? '#e2e8f0'
        : alpha(theme.palette.background.paper, 0.4),
      border: theme.palette.mode === 'light' ? '1px solid #e2e8f0' : 'none',
      '& .MuiTab-root': {
        '&.Mui-selected': {
          backgroundColor: theme.palette.primary.main,
          color: '#ffffff',
          boxShadow: '0 1px 2px rgba(0,0,0,0.3)'
        },
        '&:hover:not(.Mui-selected)': {
          backgroundColor: alpha(theme.palette.primary.main, 0.05),
          color: 'primary.main'
        }
      }
    };
  };

  return (
    <Box sx={sx}>
      <Tabs
        value={activeTab}
        onChange={onTabChange}
        variant={fullWidth ? 'fullWidth' : 'standard'}
        sx={{
          minHeight: config.minHeight,
          borderRadius: config.borderRadius,
          padding: config.containerPadding,
          ...getVariantStyles(),
          '& .MuiTabs-flexContainer': {
            gap: '4px'
          },
          '& .MuiTabs-indicator': {
            display: 'none'
          }
        }}
      >
        {tabs.map((tab, index) => {
          const isSelected = activeTab === index;
          const showBadge = (tab.badgeCount ?? 0) > 0 && !isSelected;
          const label = showBadge ? (
            <Box
              component="span"
              sx={{
                display: 'inline-flex',
                alignItems: 'center',
                gap: 0.75,
                lineHeight: 1,
              }}
            >
              <Box component="span">{tab.label}</Box>
              <Box
                component="span"
                sx={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  height: 18,
                  minWidth: 18,
                  px: '5px',
                  borderRadius: '9px',
                  backgroundColor: theme.palette.error.main,
                  color: theme.palette.error.contrastText,
                  fontSize: '0.65rem',
                  fontWeight: 700,
                  lineHeight: 1,
                }}
              >
                {(tab.badgeCount ?? 0) > 99 ? '99+' : tab.badgeCount}
              </Box>
            </Box>
          ) : (
            tab.label
          );

          return (
            <Tab
              key={index}
              label={label}
              icon={tab.icon}
              iconPosition="start"
              disabled={tab.disabled}
              sx={{
                minHeight: config.minHeight - 8,
                my: 0.2,
                textTransform: 'none',
                fontSize: config.fontSize,
                fontWeight: 600,
                color: 'text.secondary',
                backgroundColor: 'transparent',
                borderRadius: '8px',
                padding: config.padding,
                minWidth: fullWidth ? 'auto' : 'fit-content',
                gap: 0.5,
                '& .MuiTab-iconWrapper': {
                  marginRight: 0,
                  marginBottom: 0
                }
              }}
            />
          );
        })}
      </Tabs>
      
      {children}
    </Box>
  );
};

export default RoundedTabs;
